const d = $input.first().json;

const messages = {
  "Incomplete documentation": "After reviewing your submission, we are unable to proceed at this time as your application was missing required documentation. This may include tax identification records, business registration certificates, or banking details. Please review your submission, ensure all required documents are complete and accurate, and resubmit your application.",
  "Failed compliance check": "After a thorough review, your application did not meet our current compliance requirements. Remote maintains strict compliance standards across all international vendor engagements to ensure regulatory alignment. If you believe this decision was made in error or would like further clarification, our compliance team will be happy to discuss next steps.",
  "Duplicate vendor record": "Our records indicate that a vendor profile already exists for your organisation in our system. Duplicate vendor records cannot be processed to maintain the integrity of our vendor database. If you believe this is an error or your previous record requires updating, please reply and we will assist you directly.",
  "Outside service scope": "After reviewing your application, we have determined that the services described fall outside the current scope of what Remote's International Operations team is procuring at this time. This decision is not a reflection of your organisation's capabilities. We will retain your details and may reach out should our requirements change.",
  "NDA not on file": "Your application cannot be processed at this time as we do not have a signed Non-Disclosure Agreement on file for your organisation. An NDA is required before vendor onboarding can be completed. Please reply to request an NDA or attach a signed copy if you already have one."
};

const reason = d.rejectionReason;

return [{ json: {
  rejectionMessage: messages[reason],
  rejectionReason: reason
}}];
